 1	import React, { FC } from 'react';
 2	import { Trans } from 'react-i18next';
 3	
 4	import { Button, Popover } from '@patternfly/react-core';
 5	import { QuestionCircleIcon } from '@patternfly/react-icons';
 6	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
 7	
 8	type CustomRouteHelpProps = {
 9	  host: string;
10	  routerCanonicalHostname: string;
11	};
12	
13	const CustomRouteHelp: FC<CustomRouteHelpProps> = ({ host, routerCanonicalHostname }) => {
14	  const { t } = useNetworkingTranslation();
15	
16	  return (
17	    <Popover
18	      bodyContent={
19	        <div>
20	          <p>
21	            <Trans ns="plugin__networking-console-plugin" t={t}>
22	              To use a custom route, you must update your DNS provider by creating a canonical name
23	              (CNAME) record. Your CNAME record should point to your custom domain{' '}
24	              <strong>{{ host }}</strong>, to the OpenShift canonical router hostname,{' '}
25	              <strong>{{ routerCanonicalHostname }}</strong>, as the alias.
26	            </Trans>
27	          </p>
28	        </div>
29	      }
30	      headerContent={<>{t('Custom route')}</>}
31	    >
32	      <Button className="pf-m-link--align-left" type="button" variant="link">
33	        <QuestionCircleIcon /> {t('Do you need to set up custom DNS?')}
34	      </Button>
35	    </Popover>
36	  );
37	};
38	
39	export default CustomRouteHelp;

